const Q_GEOGRAPHY_1999=[{"id": "objective>Geography>1999>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main advantage of the chain survey over the prismatic compass survey is that the former</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">yields relatively more accurate results</div>", "<div style=\"font-family:Cambria;font-size:17px;\">involves highly more portable equipment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">does not require a base map</div>", "<div style=\"font-family:Cambria;font-size:17px;\">closes its boundaries with no correction</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chain survey closes its boundaries with no correction. </div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>1999>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main use of the Abney Level in surveying is to determine the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">angle of inclination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relative location</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> area coverage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spot height</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Abney levels remain in common use in several fields: In topographic surveying, to determine slope to horizontal distance calculation (angle of inclination), contour tracing and relative heights</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>1999>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A typical example of landforms produced by marine erosion is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">beach</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mud-flat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stack</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Landforms produced by marine erosion include: Blow Holes or Spouting Horns, Hanging Valleys, Stacks/Skarries/ Chimney Rock, Sea Caves, Sea Arches, sea Cliff, chasms, Wave-Cut Platform.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>1999>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the gradient of a river channel changes from a steep to a gentle angle, the main activity of the river will be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">depositing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eroding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deepening</div>", "<div style=\"font-family:Cambria;font-size:17px;\">terracing</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main activity of a river will be depositing if the slope or gradient of the river changes from steep to a gentle angle. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>1999>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The period when the earth is furthest from the sun is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">aphelion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">summer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perihelion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spring</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aphelion always happens in early July. About two weeks after the June solstice, Earth is farthest from the Sun. <br/> Perihelion always happens in early January. About two weeks after the December Solstice, Earth is closest to the sun.</div>", "topic": "PRATICAL GEOGRAPHY II : THE EARTH AS A PLANET"}, {"id": "objective>Geography>1999>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A traveller crossing the international Date Line from America to Asia at 12 midnight on Sunday, would have to change his watch to 12 midnight on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sunday</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monday</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tuesday</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Saturday</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">People traveling westward around the world must set their clocks: Back by one hour for every 15° of longitude crossed, and. Forward by 24 hours upon crossing the International Date Line. So moving from Asia to America (westward), you gain a day or 24 hours upon crossing the international Date line.</div>", "topic": "PRATICAL GEOGRAPHY II : THE EARTH AS A PLANET"}, {"id": "objective>Geography>1999>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Lakes formed as a result of landslides, screes or avalanches are known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">man-made lakes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">barrier lakes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">caldera lakes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rock-hollow lakes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Barrier lakes are formed when a landslide, mudflow, or rockfall blocks a stream or river to create a lake. The barrier that is created can be made up of a variety of materials, including soil, vegetation, and rock. The water that is backed up behind this barrier creates a lake. Therefore, lakes formed as a result of landslides, screes or avalanches are known as barrier lakes.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>1999>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In many areas, limestone rocks are resistant to water erosion on their surfaces and form uplands because of their</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">coarse and resistant minerals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low porosity and permeability</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> dense and armophous structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">joints and pervious nature</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Joints and pervious nature of limestone rocks enables the formation of uplands and the resistance to water erosion.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>1999>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fluid, basic lava flow is likely to give rise to a volcanic</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cinder cone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shield</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saddle reef</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A shield volcano is a type of volcano named for its low profile, resembling a warrior's shield lying on the ground. It is formed by the eruption of highly fluid lava, which travels farther and forms thinner flows than the more viscous lava erupted from a stratovolcan.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>1999>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Urban floods are mainly caused by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">construction of dams and barrages</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> clearance of vegetation on farmlands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blockage of drains and waterways</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishment of shelter belts</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Encroachments on drainage areas like lakes, wetlands, and riverbeds close off ways for the excess water to flow thus causing floods. <br/> Therefore, what majorly causes urban flood is the blockage of drains and waterways.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>1999>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The vegetation of the warm Temperate Eastern Margin is characterized by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">evergreen shrubs and thickets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mixed deciduous and coniferous forests</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mixed tropical rainforests and monsoonal forests</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mixed coniferous and broad-leaved evergreen forests</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At the warm Temperate Eastern Margin, the lowlands carry both ever­green broad-leaved forests and deciduous trees quite similar to those of the tropical monsoon forests. On the highlands, are various species of conifers such as pines and cypresses which are important soft­woods.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>1999>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">mixed coniferous and broad-leaved evergreen forests</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lateritic soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ferrallitic soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">podzolic soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydromorphic soil</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydromorphic soil is a heavy dark soil associated with floodable valley-bottoms. It should be noted that Hydromorphic soils are characterised by the reduction or localised segregation of iron, owing to the temporary or permanent waterlogging of the soil pores which causes a lack of oxygen over a long period. Depending on the circumstances, the ferrous iron either accumulates in the profile and gives it a greenish (or sometimes bluish) grey colour, or it is mobilised and moves very locally, forming rusty patches or concretions of ferric iron within mineral horizons.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>1999>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a major environmental problem in heavily industrialized regions?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Accelerated erosion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water pollution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Frost damage</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Acid rain</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Industrialised regions have industries with machineries which release carbon-dioxide into the atmosphere. This release is what is responsible for acid rain.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>1999>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A fog is most likely to develop when a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> warm moist wind blows over a warm current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warm moist wind blows over a cold current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cold, dry winds blows over a warm current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warm, dry winds blows over a cold current</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Warm air, moist air blows in from the south and if there is snow or cool moisture on the ground it will come in contact with the warm, moist winds. This contact between the air and ground will cause the air blowing in to become cool. Then dew point rises and creates high humidity and forms fog.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>1999>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One factor which helps to account for the dryness of the Sahara desert is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">height of the jet stream over the area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">persistence of a high pressure belt over the area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">complete absence of vegetation over much of the area</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> impact of oil production by the countries of that region</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">What accounts for the dryness of the Sahara desert is the persistence of a high pressure belt over the area.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>1999>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The circulation of the oceans and the atmosphere primarily help to redistribute and equalize global</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">flora</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fauna</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The circulation of the oceans and the atmosphere primarily help to redistribute and equalize global heat.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>1999>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Soils with well developed profiles formed mainly under the influence of the regional climate and vegetation are said to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">azonal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zonal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intrazonal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colluvial</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zonal soils are fully matured soils which have developed under the conditions of good soil drainage over a long period of time.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>1999>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Environmentalists agree that there is a general rise in sea level as a result of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">excessive rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excavation of sand from ocean beds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">global warming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">man-induced erosion along sea coasts</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sea level rise is caused primarily by two factors related to global warming: the added water from melting ice sheets and glaciers, and the expansion of seawater as it warms.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>1999>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The set of trees most suitable for pulp and paper making is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">spruce, mahogany and obeche</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fir, obeche and ebony</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spruce, fir and pine</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> pine, eucalyptus and mahogany</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The set of trees most suitable for pulp and paper making is spruce, fir, and pine. These trees are softwood trees, which have long fibers that bind together to create a strong and durable paper. Softwood trees are also faster growing and more abundant, making them a sustainable choice for paper production. The other options include hardwood trees, which have shorter fibers and are typically used for different purposes.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>1999>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The population of a certain country was observed to be 46 million males and 41 million females within a land area of about 173,000km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>. What is the average density of the population?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">503 persons per km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">351 persons per km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">266 persons per km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">237 persons per km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Population density =total population / total land area, <br/> Total population= 41 million + 46 million= 87 million. <br/> Total land area=173000km^2 <br/> population density= 87000000/173000= 502.89. Approximately 503 persons per square kilometres.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1999>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Modern satellite towns are commonly characterized by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">central city location, roomy houses and high building density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">suburban location, planned layout and spacious surroundings</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> industrial estate location, low building density and limited open spaces</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rural location, planned layout and high rise apartments</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Satellite cities or satellite towns are smaller municipalities that are adjacent to a principal city which is the core of a metropolitan area. It has a planned layout; its surroundings are spacious and it is located in the suburban settlement. <br/> </div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1999>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An extensive fertile plain with a relatively low population will most likely be characterized by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">great conurbations</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> linear, rural settlements</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> nucleated urban settlements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scattered rural settlements</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In scattered rural settlements, there is the presence of an extensive fertile plain land and few houses/population.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1999>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">International agreements in the fishing industry are necessary in order to protect whale and seal from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marauding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stock extinction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sea piracy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sea accident</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">These agreements are necessary in order to protect the organisms from stock extinction. Extinction is a situation whereby a particular species of organism no longer exists due to indiscriminate killing/hunting. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>1999>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Many industries in Europe and America have established branches in South East Asia in order to reduce</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">production costs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transport costs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw material shortages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">comparative advantage</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Generally speaking, the cost of manufacturing goods is low in Sout East Asia. Right now, in the world, India ranks number one in the list of countries with low production cost followed by China. This is due to the economic reforms in this country.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1999>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The best climate for the production of tea is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">monsoon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maritime</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equatorial</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Maritime climate supports greatly the cultivation of tea products.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1999>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Expressways mainly help intracity traffic in that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the multiple lanes can hold more traffic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vehicles can move at high speed</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> they divert traffic awasy from the city</div>", "<div style=\"font-family:Cambria;font-size:17px;\">new motor parks can be sited along them</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Expressways mainly help intracity traffic by allowing vehicles to move at high speed. They are designed for high-speed travel and they allow vehicles to move at high speed without the interference of traffic lights or intersections.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1999>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The harmattan wind in Nigeria is associated with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tropical Continental Airmass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equatorial Maritime Airmass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tropical Maritime Airmass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Polar Continental Airmass</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The tropical continental air mass, locally known as the Harmattan, is a wind originating from North Africa which crosses the Sahara into West Africa. This air mass dominates Nigeria's climate during the dry season from December to March.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>1999>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Three ethnic groups of the Niger Delta region of Nigeria are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ibibio, Tiv and Ijo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Igbo, Idoma and Ijo</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Ijo, Urhobo and Itshekiri</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Itshekiri, Igbo and Ibibio</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Niger Delta States belong to the South, South sub-region with about fourty (40) ethnic groups speaking about two hundred and fifty (250) different dialects. These ethnic groups include the Efik, Bini, Esan, Ibibio, Igbo, Annang, Oron, Ijaw, Itsekiri, Yoruba, Isoko, Urhobo, Ukwani, Kalabari, Okrika, Ogoni etc. <br/> </div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>1999>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sequence of savannah vegetation zones in Nigeria towards the northern part is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Derived, Sahel, Guinea and Sudan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Derived, Guinea, Sudan and Sahel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Derived, Sudan, Guinea and Sahel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Derived, Guinea, Sahel and Sudan</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sequence of savannah vegetation zones in Nigeria towards the northern part is derived, Guinea, Sudan and Sahel.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>1999>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Oil refineries are found in which of the following sets of states?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cross River, Rivers and Edo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Edo, Delta and Kaduna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cross River, Edo and Kaduna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rivers, Delta and Kaduna</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria has four refineries with a combined capacity of 445,000 barrels per day (bpd): one in the north at Kaduna and three in the oil-rich Niger delta region at Warri and Port Harcourt. The Port Harcourt complex consists of two plants with a combined capacity of 210,000 bpd.</div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}, {"id": "objective>Geography>1999>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, hydroelectric and thermal energies are generated respectively in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ijora and Oji river</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Afam and Ijora</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Kainji and Oji river</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kura falls and Kainji</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Oji River thermal power station in Oji River in Enugu state, Nigeria, is one of the small satellite power stations built in the South-East of Nigeria before Independence of 1960 and the commissioning of the large National Hydroelectricity power station in Kainji Dam/Jebba Dam.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>1999>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On the Jos plateau, tin and columbite are obtained mainly from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">older granites</div>", "<div style=\"font-family:Cambria;font-size:17px;\">volcanic cones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind deposits</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> alluvial deposits</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">On the Jos plateau, tin and columbite are obtained mainly from the alluvial deposits. </div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>1999>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following groups of people is not found in West Africa?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Wolof</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mandingo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mossi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shona</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Shona represents a member of a group of peoples inhabiting parts of southern Africa. The Shona comprises over three quarters of the population of Zimbabwe, and smaller groups live in South Africa, Zambia, and Mozambique.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>1999>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important gold mining town in Africa is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ilesa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Obuasi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Johannesburg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bouake</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important gold mining site is in Johannesburg. Johannesburg, affectionately called Jo'burg orJozi, is the financial and industrial metropolis of South Africa, Built on a rich history of gold mining dating back to the 19th century, it's also known as E'Goli, or the 'city of gold'.</div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}, {"id": "objective>Geography>1999>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An African port that handles more of other countries products than its own is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sofala (Beira)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cape Town</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Luanda</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mombasa</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An African port that handles more of other countries products than its own is the Port of Cape Town. </div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>1999>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Power for aluminium smelting is one of the principal objectives of the hydro-electric project in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kariba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shiroro</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Akosombo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kainji</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Power for aluminium smelting is one of the principal objectives of the hydro-electric project in Akosonbo.  <br/> Akosonbo Dam: Located at the base of Lake Volta, the Akosombo Hydroelectric Dam in southeastern Ghana draws its hydropower from the world's largest person-made lake in the world, with a surface area of 8,502km2. Initially constructed to provide electricity for the country's aluminum industry, the power plant currently has an installed capacity of 1,020 MW and provides electricity to Ghana, Togo and Benin. <br/> </div>", "topic": "REGIONAL GEOGRAPHY : INTERNATIONAL ECONOMIC COOPERATION IN WEST AFRICA ECOWAS"}, {"id": "objective>Geography>1999>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a horst in Africa is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kilimanjaro</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ruwenzori</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cameroon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Erta Ale</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Block mountains, also referred to as Horst mountains, are characterized by massive swelling of the earth' crust. A typical horst mountain in Africa is Mt. Ruwenzori in Uganda.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>1999>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The group of countries that produce most of the cocoa in West Africa is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ghana, Sierra Leone and Gambia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ghana, Cote d'Ivoire and Republic of Benin</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Ghana, Nigeria and Cote d'Ivoire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria, Cote d'Ivoire and Togo</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ghana, Nigeria and Cote d'Ivoire are the groups of countries that produce most of the cocoa in West Africa.</div>", "topic": "REGIONAL GEOGRAPHY : PLANTATION AGRICULTURE IN WEST AND EAST AFRICA"}, {"id": "objective>Geography>1999>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The two dams found in the Upper and Lower Nile respectively are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sennar and Jebbel Aulia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gezira and Sennar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aswan and Jebel Aulia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sennar and Aswan</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The two dams found in the Upper and Lower Nile respectively are the Aswan High Dam and the Jebel Aulia Dam. The Aswan High Dam is located in the Upper Nile in Egypt and it was built to control the Nile River's floodwaters, generate hydroelectric power, and store water for times of drought. The Jebel Aulia Dam is located in the Lower Nile in Sudan and it was built for irrigation purposes.</div>", "topic": "REGIONAL GEOGRAPHY : INTERNATIONAL ECONOMIC COOPERATION IN WEST AFRICA ECOWAS"}, {"id": "objective>Geography>1999>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the graph below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Which of these statements is true concerning the three rates illustrated above? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The rate were highest in 1950 and declined steadily throughthe years</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The world rate is closer to that of the more developed region than that of the less developed</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> The average world rate of growth in 2010 is less than the other two rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the rate of the more developed regions virtually declined through-out the period</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The world rate is closer to that of the more developed region than that of the less developed.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1999>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the graph below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The range of population growth in the less developed regions during the period illustrated is approximately</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.1 to 2.7%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.6 to 2.7%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.4 to 2.1%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4 to 1.6%</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The range of population growth in the less developed regions during the period illustrated is approximately 1.6% - 2.7%.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1999>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The ocean feature at point S is best described as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a submarine ridge</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> an ocean floor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an ocean dip</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a continental edge</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is an ocean dip. It can also be described as an ocean trench. <br/> Ocean trenches are long, narrow depressions on the seafloor. These chasms are the deepest parts of the ocean-and some of the deepest natural spots on Earth.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1999>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The section labelled R represents</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">An offshore beach</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a continental shelf</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a continental slope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a marine platform</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">R represents the continental slope. This is the descending slope which connects the sea floor to the continental shelf.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>1999>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> A profile drawn along LK, north east of River Aye describes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Convex slope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Concave slope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Straight slope</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Convex-concave slope</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The profile drawn along LK, north east of River Aye describes a straight slope</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>1999>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Aperi is an example of a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Confluence settlement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Foothill settlement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wet-point settlement</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Dry-point settlement</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aperi is an example of a wet point settlement. Wet-point settlement: where there is water in a dry area, e.g. spring, oasis. If water is scarce, people gather around a wet point.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1999>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The drainage pattern of the area shown is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Trellis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dendritic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radial</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Centripetal</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The drainage pattern of the area is dendritic. A dendritic drainage pattern is the most common form and looks like the branching pattern of tree roots. It develops in regions underlain by homogeneous material. That is, the subsurface geology has a similar resistance to weathering so there is no apparent control over the direction the tributaries take.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1999>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The prominent feature running approximately N.W to S.E is best described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A ridge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A spur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An escarpment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An embankment</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is a spur. A spur is a long, gently-sloping 'tongue' of ground that runs down from a hill to lower ground. Spurs often provide access to and from the high ground, for walkers, for roads, etc.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>1999>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The distance between the two confluences along River Kedi is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">9.7km</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 10.7km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11.7km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.7km</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The distance between the two confluences along River Kedi is 10.7km</div>", "topic": "PRATICAL GEOGRAPHY I : SCALE AND MEASUREMENT DISTANCES"}, {"id": "objective>Geography>1999>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">use the diagram below to answer the question  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The pyramid represents countries with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high fertility and high mortality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low fertility and high mortality <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high fertility and low mortality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low fertility and low mortality</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pyramid represents countries with high fertility and high mortality</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1999>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> use the diagram below to answer the question  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the following groups of countries is represented above?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">France, the Philippines and Kenya</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mexico, the Philippines and Jamaica</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mexico,Sweden and Japan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Japan, India and France</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mexico, Sweden and Japan are groups of countries represented above</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}];
